logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("BattleRoyaleServer")


class PlayerState(Enum):
    ALIVE = "alive"
    KNOCKED = "knocked"
    DEAD = "dead"
    SPECTATING = "spectating"


class WeaponType(Enum):
    PISTOL = "pistol"
    RIFLE = "rifle"
    SHOTGUN = "shotgun"
    SNIPER = "sniper"
    SMG = "smg"


@dataclass
class Vector2:
    x: float = 0.0
    y: float = 0.0

    def distance_to(self, other: 'Vector2') -> float:
        return math.sqrt((self.x - other.x) ** 2 + (self.y - other.y) ** 2)

    def to_dict(self):
        return {"x": self.x, "y": self.y}

    @staticmethod
    def from_dict(d):
        return Vector2(x=d.get("x", 0), y=d.get("y", 0))


@dataclass
class Projectile:
    id: str
    owner_id: str
    position: Vector2
    velocity: Vector2
    damage: float
    weapon_type: str
    created_at: float
    ttl: float = 3.0

    def to_dict(self):
        return {
            "id": self.id,
            "owner_id": self.owner_id,
            "position": self.position.to_dict(),
            "velocity": self.velocity.to_dict(),
            "damage": self.damage,
            "weapon_type": self.weapon_type,
        }


@dataclass
class LootItem:
    id: str
    item_type: str
    position: Vector2
    quantity: int = 1
    picked_up: bool = False

    def to_dict(self):
        return {
            "id": self.id,
            "item_type": self.item_type,
            "position": self.position.to_dict(),
            "quantity": self.quantity,
        }


@dataclass
class Obstacle:
    id: str
    position: Vector2
    width: float
    height: float
    destructible: bool = False
    health: float = 100.0

    def to_dict(self):
        return {
            "id": self.id,
            "position": self.position.to_dict(),
            "width": self.width,
            "height": self.height,
            "destructible": self.destructible,
            "health": self.health,
        }

    def contains_point(self, point: Vector2) -> bool:
        half_w = self.width / 2
        half_h = self.height / 2
        return (self.position.x - half_w <= point.x <= self.position.x + half_w and
                self.position.y - half_h <= point.y <= self.position.y + half_h)


@dataclass
class Player:
    id: str
    name: str
    position: Vector2 = field(default_factory=Vector2)
    velocity: Vector2 = field(default_factory=Vector2)
    rotation: float = 0.0
    health: float = 100.0
    shield: float = 0.0
    state: PlayerState = PlayerState.ALIVE
    weapon: WeaponType = WeaponType.PISTOL
    ammo: Dict[str, int] = field(default_factory=lambda: {
        "pistol": 30, "rifle": 0, "shotgun": 0, "sniper": 0, "smg": 0
    })
    inventory: List[str] = field(default_factory=list)
    kills: int = 0
    damage_dealt: float = 0.0
    last_input_seq: int = 0
    last_activity: float = 0.0
    speed: float = 200.0
    is_sprinting: bool = False
    is_crouching: bool = False

    def to_dict(self):
        return {
            "id": self.id,
            "name": self.name,
            "position": self.position.to_dict(),
            "velocity": self.velocity.to_dict(),
            "rotation": self.rotation,
            "health": self.health,
            "shield": self.shield,
            "state": self.state.value,
            "weapon": self.weapon.value,
            "kills": self.kills,
            "is_sprinting": self.is_sprinting,
            "is_crouching": self.is_crouching,
        }

    def to_full_dict(self):
        d = self.to_dict()
        d["ammo"] = self.ammo
        d["inventory"] = self.inventory
        d["damage_dealt"] = self.damage_dealt
        return d


@dataclass
class Zone:
    center: Vector2
    current_radius: float
    target_radius: float
    shrink_rate: float
    damage_per_second: float
    phase: int

    def to_dict(self):
        return {
            "center": self.center.to_dict(),
            "current_radius": self.current_radius,
            "target_radius": self.target_radius,
            "shrink_rate": self.shrink_rate,
            "damage_per_second": self.damage_per_second,
            "phase": self.phase,
        }

    def is_inside(self, pos: Vector2) -> bool:
        return self.center.distance_to(pos) <= self.current_radius


class GamePhase(Enum):
    WAITING = "waiting"
    COUNTDOWN = "countdown"
    DROPPING = "dropping"
    PLAYING = "playing"
    FINAL_CIRCLE = "final_circle"
    ENDED = "ended"


WEAPON_STATS = {
    WeaponType.PISTOL: {"damage": 15, "fire_rate": 0.4, "range": 400, "speed": 800, "ammo_cost": 1},
    WeaponType.RIFLE: {"damage": 25, "fire_rate": 0.1, "range": 600, "speed": 900, "ammo_cost": 1},
    WeaponType.SHOTGUN: {"damage": 80, "fire_rate": 0.8, "range": 150, "speed": 600, "ammo_cost": 1},
    WeaponType.SNIPER: {"damage": 90, "fire_rate": 1.5, "range": 1200, "speed": 1200, "ammo_cost": 1},
    WeaponType.SMG: {"damage": 12, "fire_rate": 0.07, "range": 350, "speed": 750, "ammo_cost": 1},
}

MAP_SIZE = 4000.0
MIN_PLAYERS_TO_START = 2
MAX_PLAYERS = 100
TICK_RATE = 20
BROADCAST_RATE = 20
FULL_STATE_RATE = 2
AFK_TIMEOUT = 120.0


class BattleRoyaleServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.projectiles: Dict[str, Projectile] = {}
        self.loot_items: Dict[str, LootItem] = {}
        self.obstacles: Dict[str, Obstacle] = {}
        self.kill_feed: List[Dict] = []
        self.game_phase: GamePhase = GamePhase.WAITING
        self.zone: Zone = Zone(
            center=Vector2(MAP_SIZE / 2, MAP_SIZE / 2),
            current_radius=MAP_SIZE / 2,
            target_radius=MAP_SIZE / 2,
            shrink_rate=0,
            damage_per_second=1,
            phase=0,
        )
        self.zone_phases = [
            {"delay": 60, "shrink_time": 30, "target_ratio": 0.7, "damage": 1},
            {"delay": 50, "shrink_time": 25, "target_ratio": 0.5, "damage": 2},
            {"delay": 40, "shrink_time": 20, "target_ratio": 0.35, "damage": 5},
            {"delay": 30, "shrink_time": 15, "target_ratio": 0.2, "damage": 8},
            {"delay": 20, "shrink_time": 10, "target_ratio": 0.1, "damage": 12},
            {"delay": 15, "shrink_time": 8, "target_ratio": 0.05, "damage": 20},
            {"delay": 10, "shrink_time": 5, "target_ratio": 0.01, "damage": 50},
        ]
        self.zone_timer: float = 0
        self.zone_shrinking: bool = False
        self.game_start_time: float = 0
        self.countdown_timer: float = 0
        self.last_tick_time: float = 0
        self.tick_count: int = 0
        self.last_fire_times: Dict[str, float] = {}
        self.player_input_buffers: Dict[str, List[Dict]] = {}
        self.events_queue: List[Dict] = []
        self._generate_map()

    def _generate_map(self):
        random.seed(42)
        # Generate obstacles (buildings, walls, rocks)
        obstacle_configs = [
            ("building", 80, 80, True, 500),
            ("wall", 120, 10, True, 200),
            ("rock", 30, 30, False, 0),
        ]
        for i in range(150):
            config = random.choice(obstacle_configs)
            obs = Obstacle(
                id=f"obs_{i}",
                position=Vector2(
                    random.uniform(100, MAP_SIZE - 100),
                    random.uniform(100, MAP_SIZE - 100),
                ),
                width=config[1] + random.uniform(-10, 10),
                height=config[2] + random.uniform(-10, 10),
                destructible=config[3],
                health=config[4] if config[3] else float('inf'),
            )
            self.obstacles[obs.id] = obs

        # Generate loot
        loot_types = ["rifle", "shotgun", "sniper", "smg", "shield_potion",
                       "medkit", "ammo_rifle", "ammo_shotgun", "ammo_sniper", "ammo_smg"]
        for i in range(300):
            item = LootItem(
                id=f"loot_{i}",
                item_type=random.choice(loot_types),
                position=Vector2(
                    random.uniform(50, MAP_SIZE - 50),
                    random.uniform(50, MAP_SIZE - 50),
                ),
                quantity=random.randint(1, 3) if "ammo" in random.choice(loot_types) else 1,
            )
            self.loot_items[item.id] = item

    def _get_spawn_position(self) -> Vector2:
        margin = 200
        for _ in range(50):
            pos = Vector2(
                random.uniform(margin, MAP_SIZE - margin),
                random.uniform(margin, MAP_SIZE - margin),
            )
            # Check not inside obstacle
            inside = False
            for obs in self.obstacles.values():
                if obs.contains_point(pos):
                    inside = True
                    break
            if not inside:
                return pos
        return Vector2(MAP_SIZE / 2, MAP_SIZE / 2)

    def _line_of_sight_blocked(self, p1: Vector2, p2: Vector2) -> bool:
        """Ray-cast between two points, check if any obstacle blocks LOS."""
        dx = p2.x - p1.x
        dy = p2.y - p1.y
        dist = math.sqrt(dx * dx + dy * dy)
        if dist == 0:
            return False

        steps = int(dist / 10)  # Check every 10 units
        steps = max(steps, 1)

        for i in range(1, steps + 1):
            t = i / steps
            check_point = Vector2(p1.x + dx * t, p1.y + dy * t)
            for obs in self.obstacles.values():
                if obs.contains_point(check_point):
                    return True
        return False

    async def register_player(self, websocket, name: str) -> Optional[Player]:
        if len(self.players) >= MAX_PLAYERS:
            await websocket.send(json.dumps({"type": "error", "message": "Server full"}))
            return None

        if self.game_phase not in (GamePhase.WAITING, GamePhase.COUNTDOWN):
            await websocket.send(json.dumps({"type": "error", "message": "Game already in progress"}))
            return None

        player_id = str(uuid.uuid4())[:8]
        spawn_pos = self._get_spawn_position()

        player = Player(
            id=player_id,
            name=name,
            position=spawn_pos,
            last_activity=time.time(),
        )

        self.players[player_id] = player
        self.connections[player_id] = websocket
        self.player_input_buffers[player_id] = []
        self.last_fire_times[player_id] = 0

        logger.info(f"Player {name} ({player_id}) connected. Total: {len(self.players)}")

        # Send welcome message with full map data
        await websocket.send(json.dumps({
            "type": "welcome",
            "player_id": player_id,
            "map_size": MAP_SIZE,
            "obstacles": [obs.to_dict() for obs in self.obstacles.values()],
            "tick_rate": TICK_RATE,
        }))

        # Broadcast player joined
        await self._broadcast_event({
            "type": "player_joined",
            "player": player.to_dict(),
            "player_count": len(self.players),
        })

        # Check if we should start countdown
        if (self.game_phase == GamePhase.WAITING and
                len(self.players) >= MIN_PLAYERS_TO_START):
            self.game_phase = GamePhase.COUNTDOWN
            self.countdown_timer = 10.0
            await self._broadcast_event({
                "type": "countdown_start",
                "seconds": self.countdown_timer,
            })

        return player

    async def unregister_player(self, player_id: str):
        if player_id in self.players:
            player = self.players[player_id]
            player.state = PlayerState.DEAD
            logger.info(f"Player {player.name} ({player_id}) disconnected.")

            del self.players[player_id]
            if player_id in self.connections:
                del self.connections[player_id]
            if player_id in self.player_input_buffers:
                del self.player_input_buffers[player_id]
            if player_id in self.last_fire_times:
                del self.last_fire_times[player_id]

            await self._broadcast_event({
                "type": "player_left",
                "player_id": player_id,
                "player_count": len(self.players),
            })

            # Check win condition
            await self._check_win_condition()

    def process_input(self, player_id: str, input_data: Dict):
        if player_id not in self.players:
            return
        player = self.players[player_id]
        if player.state != PlayerState.ALIVE:
            return

        player.last_activity = time.time()
        player.last_input_seq = input_data.get("seq", 0)

        # Movement
        move_x = input_data.get("move_x", 0)
        move_y = input_data.get("move_y", 0)
        player.rotation = input_data.get("rotation", player.rotation)
        player.is_sprinting = input_data.get("sprint", False)
        player.is_crouching = input_data.get("crouch", False)

        speed = player.speed
        if player.is_sprinting:
            speed *= 1.5
        if player.is_crouching:
            speed *= 0.5

        # Normalize movement vector
        mag = math.sqrt(move_x * move_x + move_y * move_y)
        if mag > 0:
            move_x /= mag
            move_y /= mag

        player.velocity = Vector2(move_x * speed, move_y * speed)

        # Actions
        action = input_data.get("action")
        if action == "fire":
            self._handle_fire(player_id)
        elif action == "reload":
            self._handle_reload(player_id)
        elif action == "pickup":
            self._handle_pickup(player_id)
        elif action == "switch_weapon":
            weapon_name = input_data.get("weapon", "pistol")
            try:
                player.weapon = WeaponType(weapon_name)
            except ValueError:
                pass
        elif action == "use_item":
            self._handle_use_item(player_id, input_data.get("item_type"))

    def _handle_fire(self, player_id: str):
        player = self.players[player_id]
        now = time.time()
        weapon_stats = WEAPON_STATS[player.weapon]

        # Check fire rate
        if now - self.last_fire_times.get(player_id, 0) < weapon_stats["fire_rate"]:
            return

        # Check ammo
        ammo_key = player.weapon.value
        if player.ammo.get(ammo_key, 0) < weapon_stats["ammo_cost"]:
            return

        player.ammo[ammo_key] -= weapon_stats["ammo_cost"]
        self.last_fire_times[player_id] = now

        # Create projectile
        angle = player.rotation
        vel_x = math.cos(angle) * weapon_stats["speed"]
        vel_y = math.sin(angle) * weapon_stats["speed"]

        # Slight offset from player position
        offset = 20
        start_x = player.position.x + math.cos(angle) * offset
        start_y = player.position.y + math.sin(angle) * offset

        proj = Projectile(
            id=str(uuid.uuid4())[:8],
            owner_id=player_id,
            position=Vector2(start_x, start_y),
            velocity=Vector2(vel_x, vel_y),
            damage=weapon_stats["damage"],
            weapon_type=player.weapon.value,
            created_at=now,
            ttl=weapon_stats["range"] / weapon_stats["speed"],
        )

        # Shotgun fires multiple pellets
        if player.weapon == WeaponType.SHOTGUN:
            for spread_i in range(5):
                spread_angle = angle + random.uniform(-0.15, 0.15)
                pellet_vel_x = math.cos(spread_angle) * weapon_stats["speed"]
                pellet_vel_y = math.sin(spread_angle) * weapon_stats["speed"]
                pellet = Projectile(
                    id=str(uuid.uuid4())[:8],
                    owner_id=player_id,
                    position=Vector2(start_x, start_y),
                    velocity=Vector2(pellet_vel_x, pellet_vel_y),
                    damage=weapon_stats["damage"] / 5,
                    weapon_type=player.weapon.value,
                    created_at=now,
                    ttl=weapon_stats["range"] / weapon_stats["speed"],
                )
                self.projectiles[pellet.id] = pellet
        else:
            self.projectiles[proj.id] = proj

        self.events_queue.append({
            "type": "shot_fired",
            "player_id": player_id,
            "position": player.position.to_dict(),
            "rotation": angle,
            "weapon": player.weapon.value,
        })

    def _handle_reload(self, player_id: str):
        # Simplified reload - instant for now
        player = self.players[player_id]
        ammo_key = player.weapon.value
        max_ammo = {"pistol": 30, "rifle": 90, "shotgun": 20, "sniper": 15, "smg": 120}
        player.ammo[ammo_key] = max_ammo.get(ammo_key, 30)

    def _handle_pickup(self, player_id: str):
        player = self.players[player_id]
        pickup_range = 50

        for item_id, item in list(self.loot_items.items()):
            if item.picked_up:
                continue
            if player.position.distance_to(item.position) <= pickup_range:
                item.picked_up = True

                if item.item_type in ("rifle", "shotgun", "sniper", "smg"):
                    try:
                        player.weapon = WeaponType(item.item_type)
                        player.ammo[item.item_type] = player.ammo.get(item.item_type, 0) + 30
                    except ValueError:
                        pass
                elif item.item_type.startswith("ammo_"):
                    ammo_type = item.item_type.replace("ammo_", "")
                    player.ammo[ammo_type] = player.ammo.get(ammo_type, 0) + 30 * item.quantity
                elif item.item_type == "shield_potion":
                    player.shield = min(100, player.shield + 50)
                elif item.item_type == "medkit":
                    player.health = min(100, player.health + 50)

                player.inventory.append(item.item_type)

                self.events_queue.append({
                    "type": "item_picked_up",
                    "player_id": player_id,
                    "item_id": item_id,
                    "item_type": item.item_type,
                })
                break

    def _handle_use_item(self, player_id: str, item_type: Optional[str]):
        if not item_type:
            return
        player = self.players[player_id]
        if item_type in player.inventory:
            player.inventory.remove(item_type)
            if item_type == "medkit":
                player.health = min(100, player.health + 50)
            elif item_type == "shield_potion":
                player.shield = min(100, player.shield + 50)

    def _apply_damage(self, target: Player, damage: float, attacker_id: str):
        if target.state != PlayerState.ALIVE:
            return

        # Shield absorbs damage first
        if target.shield > 0:
            shield_damage = min(target.shield, damage)
            target.shield -= shield_damage
            damage -= shield_damage

        target.health -= damage

        if attacker_id in self.players:
            self.players[attacker_id].damage_dealt += damage

        if target.health <= 0:
            target.health = 0
            target.state = PlayerState.DEAD

            if attacker_id in self.players:
                self.players[attacker_id].kills += 1

            kill_event = {
                "type": "player_killed",
                "victim_id": target.id,
                "victim_name": target.name,
                "killer_id": attacker_id,
                "killer_name": self.players[attacker_id].name if attacker_id in self.players else "Zone",
            }
            self.kill_feed.append(kill_event)
            self.events_queue.append(kill_event)

            # Drop loot on death
            for item_name in target.inventory:
                loot = LootItem(
                    id=str(uuid.uuid4())[:8],
                    item_type=item_name,
                    position=Vector2(
                        target.position.x + random.uniform(-20, 20),
                        target.position.y + random.uniform(-20, 20),
                    ),
                )
                self.loot_items[loot.id] = loot

    def update(self, dt: float):
        if self.game_phase == GamePhase.WAITING:
            return
        elif self.game_phase == GamePhase.COUNTDOWN:
            self.countdown_timer -= dt
            if self.countdown_timer <= 0:
                self.game_phase = GamePhase.PLAYING
                self.game_start_time = time.time()
                self.zone_timer = self.zone_phases[0]["delay"]
                self.events_queue.append({"type": "game_started"})
            return
        elif self.game_phase == GamePhase.ENDED:
            return

        # Update player positions
        for player in self.players.values():
            if player.state != PlayerState.ALIVE:
                continue

            new_x = player.position.x + player.velocity.x * dt
            new_y = player.position.y + player.velocity.y * dt

            # Clamp to map bounds
            new_x = max(0, min(MAP_SIZE, new_x))
            new_y = max(0, min(MAP_SIZE, new_y))

            # Collision with obstacles
            new_pos = Vector2(new_x, new_y)
            collided = False
            for obs in self.obstacles.values():
                if obs.contains_point(new_pos):
                    collided = True
                    break

            if not collided:
                player.position = new_pos

        # Update projectiles
        projectiles_to_remove = []
        for proj_id, proj in list(self.projectiles.items()):
            proj.position.x += proj.velocity.x * dt
            proj.position.y += proj.velocity.y * dt

            # Check TTL
            if time.time() - proj.created_at > proj.ttl:
                projectiles_to_remove.append(proj_id)
                continue

            # Check out of bounds
            if (proj.position.x < 0 or proj.position.x > MAP_SIZE or
                    proj.position.y < 0 or proj.position.y > MAP_SIZE):
                projectiles_to_remove.append(proj_id)
                continue

            # Check obstacle collision
            hit_obstacle = False
            for obs in self.obstacles.values():
                if obs.contains_point(proj.position):
                    if obs.destructible:
                        obs.health -= proj.damage
                        if obs.health <= 0:
                            self.events_queue.append({
                                "type": "obstacle_destroyed",
                                "obstacle_id": obs.id,
                            })
                    hit_obstacle = True
                    break

            if hit_obstacle:
                projectiles_to_remove.append(proj_id)
                continue

            # Check player collision
            hit_player = False
            for player in self.players.values():
                if player.id == proj.owner_id:
                    continue
                if player.state != PlayerState.ALIVE:
                    continue

                hit_radius = 15  # Player hitbox radius
                if proj.position.distance_to(player.position) <= hit_radius:
                    self._apply_damage(player, proj.damage, proj.owner_id)
                    self.events_queue.append({
                        "type": "player_hit",
                        "target_id": player.id,
                        "attacker_id": proj.owner_id,
                        "damage": proj.damage,
                        "position": proj.position.to_dict(),
                    })
                    hit_player = True
                    break

            if hit_player:
                projectiles_to_remove.append(proj_id)

        for proj_id in projectiles_to_remove:
            if proj_id in self.projectiles:
                del self.projectiles[proj_id]

        # Remove destroyed obstacles
        destroyed = [oid for oid, obs in self.obstacles.items()
                     if obs.destructible and obs.health <= 0]
        for oid in destroyed:
            del self.obstacles[oid]

        # Update zone
        self._update_zone(dt)

        # Zone damage
        for player in self.players.values():
            if player.state != PlayerState.ALIVE:
                continue
            if not self.zone.is_inside(player.position):
                self._apply_damage(player, self.zone.damage_per_second * dt, "zone")

        # AFK check
        now = time.time()
        for player in self.players.values():
            if player.state == PlayerState.ALIVE and now - player.last_activity > AFK_TIMEOUT:
                player.state = PlayerState.DEAD
                self.events_queue.append({
                    "type": "player_killed",
                    "victim_id": player.id,
                    "victim_name": player.name,
                    "killer_id": "afk",
                    "killer_name": "AFK Timer",
                })

    def _update_zone(self, dt: float):
        if self.zone.phase >= len(self.zone_phases):
            return

        if self.zone_shrinking:
            phase_config = self.zone_phases[self.zone.phase]
            shrink_amount = self.zone.shrink_rate * dt
            self.zone.current_radius = max(
                self.zone.target_radius,
                self.zone.current_radius - shrink_amount
            )

            # Slowly move center toward a random offset for variety
            if self.zone.current_radius <= self.zone.target_radius:
                self.zone_shrinking = False
                self.zone.phase += 1
                if self.zone.phase < len(self.zone_phases):
                    self.zone_timer = self.zone_phases[self.zone.phase]["delay"]
                    next_config = self.zone_phases[self.zone.phase]
                    self.zone.damage_per_second = next_config["damage"]
                    self.events_queue.append({
                        "type": "zone_phase_change",
                        "phase": self.zone.phase,
                        "zone": self.zone.to_dict(),
                    })
                else:
                    self.game_phase = GamePhase.FINAL_CIRCLE
        else:
            self.zone_timer -= dt
            if self.zone_timer <= 0:
                phase_config = self.zone_phases[self.zone.phase]
                self.zone.target_radius = (MAP_SIZE / 2) * phase_config["target_ratio"]
                shrink_time = phase_config["shrink_time"]
                self.zone.shrink_rate = (self.zone.current_radius - self.zone.target_radius) / shrink_time
                self.zone.damage_per_second = phase_config["damage"]
                self.zone_shrinking = True

                # Shift center slightly
                max_shift = (self.zone.current_radius - self.zone.target_radius) * 0.3
                self.zone.center.x += random.uniform(-max_shift, max_shift)
                self.zone.center.y += random.uniform(-max_shift, max_shift)
                self.zone.center.x = max(self.zone.target_radius, min(MAP_SIZE - self.zone.target_radius, self.zone.center.x))
                self.zone.center.y = max(self.zone.target_radius, min(MAP_SIZE - self.zone.target_radius, self.zone.center.y))

                self.events_queue.append({
                    "type": "zone_shrinking",
                    "zone": self.zone.to_dict(),
                })

    async def _check_win_condition(self):
        alive_players = [p for p in self.players.values() if p.state == PlayerState.ALIVE]
        if len(alive_players) <= 1 and self.game_phase in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE):
            self.game_phase = GamePhase.ENDED
            winner = alive_players[0] if alive_players else None
            await self._broadcast_event({
                "type": "game_over",
                "winner": winner.to_dict() if winner else None,
                "final_standings": self._get_standings(),
            })

    def _get_standings(self) -> List[Dict]:
        all_players = sorted(
            self.players.values(),
            key=lambda p: (p.state == PlayerState.ALIVE, p.kills, p.damage_dealt),
            reverse=True,
        )
        return [
            {
                "player_id": p.id,
                "name": p.name,
                "kills": p.kills,
                "damage_dealt": p.damage_dealt,
                "state": p.state.value,
            }
            for p in all_players
        ]

    def build_game_state(self) -> Dict:
        """Build the full game state broadcast to all clients.
        All player positions are sent to all clients.
        Clients filter rendering based on distance and LOS."""
        return {
            "type": "game_state",
            "timestamp": time.time(),
            "tick": self.tick_count,
            "game_phase": self.game_phase.value,
            "players": {pid: p.to_dict() for pid, p in self.players.items()},
            "projectiles": [p.to_dict() for p in self.projectiles.values()],
            "zone": self.zone.to_dict(),
            "zone_timer": max(0, self.zone_timer),
            "zone_shrinking": self.zone_shrinking,
            "alive_count": sum(1 for p in self.players.values() if p.state == PlayerState.ALIVE),
        }

    def build_full_state_for_player(self, player_id: str) -> Dict:
        """Build full state including private player data for a specific client.
        Includes all positions for client-side distance/LOS filtering."""
        if player_id not in self.players:
            return {}

        player = self.players[player_id]
        state = self.build_game_state()
        state["type"] = "full_state"

        # Add private data for this player
        state["self"] = player.to_full_dict()
        state["self"]["last_input_seq"] = player.last_input_seq

        # Provide LOS hints from server to help client rendering
        # Client can use these hints but ultimately decides what to render
        los_data = {}
        for other_id, other in self.players.items():
            if other_id == player_id:
                continue
            if other.state != PlayerState.ALIVE:
                los_data[other_id] = {"visible": False, "reason": "dead"}
                continue

            distance = player.position.distance_to(other.position)
            blocked = self._line_of_sight_blocked(player.position, other.position)

            los_data[other_id] = {
                "distance": round(distance, 1),
                "los_blocked": blocked,
                "visible": not blocked,
            }

        state["los_hints"] = los_data

        # Include nearby loot
        loot_range = 500
        nearby_loot = []
        for item in self.loot_items.values():
            if not item.picked_up and player.position.distance_to(item.position) <= loot_range:
                nearby_loot.append(item.to_dict())
        state["nearby_loot"] = nearby_loot

        # Recent kill feed
        state["kill_feed"] = self.kill_feed[-10:]

        return state

    async def _broadcast_event(self, event: Dict):
        message = json.dumps(event)
        disconnected = []
        for pid, ws in self.connections.items():
            try:
                await ws.send(message)
            except websockets.exceptions.ConnectionClosed:
                disconnected.append(pid)
        for pid in disconnected:
            await self.unregister_player(pid)

    async def _send_to_player(self, player_id: str, data: Dict):
        if player_id in self.connections:
            try:
                await self.connections[player_id].send(json.dumps(data))
            except websockets.exceptions.ConnectionClosed:
                await self.unregister_player(player_id)

    async def broadcast_game_state(self):
        """Send game state to all connected clients."""
        game_state = self.build_game_state()
        message = json.dumps(game_state)
        disconnected = []
        for pid, ws in self.connections.items():
            try:
                await ws.send(message)
            except websockets.exceptions.ConnectionClosed:
                disconnected.append(pid)
        for pid in disconnected:
            await self.unregister_player(pid)

    async def broadcast_full_state(self):
        """Send personalized full state to each client for optimized rendering."""
        disconnected = []
        for pid, ws in list(self.connections.items()):
            try:
                full_state = self.build_full_state_for_player(pid)
                if full_state:
                    await ws.send(json.dumps(full_state))
            except websockets.exceptions.ConnectionClosed:
                disconnected.append(pid)
        for pid in disconnected:
            await self.unregister_player(pid)

    async def broadcast_events(self):
        """Broadcast queued events to all clients."""
        if not self.events_queue:
            return
        for event in self.events_queue:
            await self._broadcast_event(event)
        self.events_queue.clear()

    async def game_loop(self):
        """Main game loop running at TICK_RATE Hz."""
        logger.info(f"Game loop started at {TICK_RATE} tick/s")
        tick_interval = 1.0 / TICK_RATE
        broadcast_interval = 1.0 / BROADCAST_RATE
        full_state_interval = 1.0 / FULL_STATE_RATE

        last_broadcast = time.time()
        last_full_state = time.time()
        self.last_tick_time = time.time()

        while True:
            now = time.time()
            dt = now - self.last_tick_time
            self.last_tick_time = now
            self.tick_count += 1

            # Update game simulation
            self.update(dt)

            # Check win condition
            if self.game_phase in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE):
                await self._check_win_condition()

            # Broadcast events immediately
            await self.broadcast_events()

            # Regular game state broadcast
            if now - last_broadcast >= broadcast_interval:
                await self.broadcast_game_state()
                last_broadcast = now

            # Full state broadcast (less frequent, includes LOS hints and private data)
            if now - last_full_state >= full_state_interval:
                await self.broadcast_full_state()
                last_full_state = now

            # Sleep to maintain tick rate
            elapsed = time.time() - now
            sleep_time = max(0, tick_interval - elapsed)
            await asyncio.sleep(sleep_time)

    async def reset_game(self):
        """Reset the game for a new round."""
        self.projectiles.clear()
        self.kill_feed.clear()
        self.events_queue.clear()
        self.game_phase = GamePhase.WAITING
        self.zone = Zone(
            center=Vector2(MAP_SIZE / 2, MAP_SIZE / 2),
            current_radius=MAP_SIZE / 2,
            target_radius=MAP_SIZE / 2,
            shrink_rate=0,
            damage_per_second=1,
            phase=0,
        )
        self.zone_timer = 0
        self.zone_shrinking = False
        self.tick_count = 0

        # Reset loot
        for item in self.loot_items.values():
            item.picked_up = False

        # Regenerate destroyed obstacles
        self.obstacles.clear()
        self._generate_map()

        # Reset players
        for player in self.players.values():
            player.position = self._get_spawn_position()
            player.velocity = Vector2()
            player.health = 100
            player.shield = 0
            player.state = PlayerState.ALIVE
            player.weapon = WeaponType.PISTOL
            player.ammo = {"pistol": 30, "rifle": 0, "shotgun": 0, "sniper": 0, "smg": 0}
            player.inventory.clear()
            player.kills = 0
            player.damage_dealt = 0

        await self._broadcast_event({"type": "game_reset"})

        if len(self.players) >= MIN_PLAYERS_TO_START:
            self.game_phase = GamePhase.COUNTDOWN
            self.countdown_timer = 10.0
            await self._broadcast_event({
                "type": "countdown_start",
                "seconds": self.countdown_timer,
            })


server = BattleRoyaleServer()


async def handle_client(websocket, path=None):
    player_id = None
    try:
        # Wait for join message
        raw = await asyncio.wait_for(websocket.recv(), timeout=10.0)
        msg = json.loads(raw)

        if msg.get("type") != "join":
            await websocket.send(json.dumps({"type": "error", "message": "Expected join message"}))
            return

        name = msg.get("name", f"Player_{random.randint(1000, 9999)}")
        player = await server.register_player(websocket, name)
        if not player:
            return
        player_id = player.id

        # Main message loop
        async for raw_msg in websocket:
            try:
                msg = json.loads(raw_msg)
                msg_type = msg.get("type")

                if msg_type == "input":
                    server.process_input(player_id, msg)
                elif msg_type == "ping":
                    await websocket.send(json.dumps({
                        "type": "pong",
                        "client_time": msg.get("client_time"),
                        "server_time": time.time(),
                    }))
                elif msg_type == "chat":
                    await server._broadcast_event({
                        "type": "chat",
                        "player_id": player_id,
                        "name": player.name,
                        "message": msg.get("message", "")[:200],
                    })
                elif msg_type == "request_full_state":
                    full_state = server.build_full_state_for_player(player_id)
                    await websocket.send(json.dumps(full_state))
            except json.JSONDecodeError:
                logger.warning(f"Invalid JSON from {player_id}")
            except Exception as e:
                logger.error(f"Error processing message from {player_id}: {e}")

    except websockets.exceptions.ConnectionClosed:
        pass
    except asyncio.TimeoutError:
        logger.warning("Client timed out during handshake")
    except Exception as e:
        logger.error(f"Unexpected error: {e}")
    finally:
        if player_id:
            await server.unregister_player(player_id)


async def admin_handler(websocket, path=None):
    """Admin websocket endpoint for server management."""
    try:
        async for raw_msg in websocket:
            msg = json.loads(raw_msg)
            if msg.get("type") == "status":
                status = {
                    "type": "status",
                    "players": len(server.players),
                    "game_phase": server.game_phase.value,
                    "tick": server.tick_count,
                    "projectiles": len(server.projectiles),
                    "zone": server.zone.to_dict(),
                    "alive": sum(1 for p in server.players.values() if p.state == PlayerState.ALIVE),
                }
                await websocket.send(json.dumps(status))
            elif msg.get("type") == "reset":
                await server.reset_game()
                await websocket.send(json.dumps({"type": "ok", "message": "Game reset"}))
            elif msg.get("type") == "force_start":
                if server.game_phase == GamePhase.WAITING:
                    server.game_phase = GamePhase.COUNTDOWN
                    server.countdown_timer = 5.0
                    await server._broadcast_event({
                        "type": "countdown_start",
                        "seconds": server.countdown_timer,
                    })
                await websocket.send(json.dumps({"type": "ok", "message": "Force starting"}))
    except websockets.exceptions.ConnectionClosed:
        pass


async def main():
    logger.info("Starting Battle Royale Server...")

    # Start game loop
    game_task = asyncio.create_task(server.game_loop())

    # Start game WebSocket server
    game_server = await websockets.serve(
        handle_client,
        "0.0.0.0",
        8765,
        ping_interval=20,
        ping_timeout=10,
        max_size=2**16,
    )
    logger.info("Game server listening on ws://0.0.0.0:8765")

    # Start admin WebSocket server
    admin_server = await websockets.serve(
        admin_handler,
        "0.0.0.0",
        8766,
        ping_interval=20,
        ping_timeout=10,
    )
    logger.info("Admin server listening on ws://0.0.0.0:8766")

    # Auto-restart game after it ends
    async def auto_restart():
        while True:
            await asyncio.sleep(5)
            if server.game_phase == GamePhase.ENDED:
                logger.info("Game ended. Restarting in 15 seconds...")
                await asyncio.sleep(15)
                await server.reset_game()

    restart_task = asyncio.create_task(auto_restart())

    try:
        await asyncio.gather(
            game_task,
            game_server.wait_closed(),
            admin_server.wait_closed(),
            restart_task,
        )
    except KeyboardInterrupt:
        logger.info("Server shutting down...")
    finally:
        game_server.close()
        admin_server.close()


if __name__ == "__main__":
    asyncio.run(main())